local G = DYCLegendary local require = G.DYCModRequire local enchantmentSystem = require( "dyc_enchantments" ) local enchantmentList = enchantmentSystem.list local bonusList = enchantmentSystem.bonusList local Buff = require( "dyc_buffs" ) local TableContains = G.lib.TableContains local TableCount = G.lib.TableCount local TableAdd = G.lib.TableAdd local TableRemoveValue = G.lib.TableRemoveValue local Clamp = G.lib.Clamp local rarityColors = G.rarityColors local function IsString(o) return o ~= nil and type(o) == "string" end local function IsNonEmptyString(o) return IsString(o) and #o > 0x0 end local function IsTable(o) return o ~= nil and type(o) == "table" end local function RandomFloat(min, max) max = max or 1.0; min = min or 0; return math.random() * (max - min) + min end local function RarityValueToString(rarity) if rarity < 0x19 then return "common" elseif rarity < 0x32 then return "uncommon" elseif rarity < 0x4b then return "rare" elseif rarity <= 0x64 then return "unique" else return "legendary" end end local function QualityValueToString(q) if q < 0.75 then return "verylow" elseif q < 0.9 then return "low" elseif q <= 1.1 then return "medium" elseif q <= 1.25 then return "high" else return "veryhigh" end end function EntityScript:GetRarityColor() local rarity = self:GetRarity() local rarityStr = RarityValueToString(rarity) return rarityStr and rarityColors[string.lower(rarityStr)] or rarityColors["common"] end function EntityScript:GetRarityString() local rarity = self:GetRarity() local rarityStr = RarityValueToString(rarity) local l = G.localization return rarityStr and l:GetString(rarityStr) or "" end function EntityScript:GetRarity() local encs = self:GetEnchantments() local grade, gradeSum = 0x0, 0x0 local coeff = 0.4 local isLegendary = false for k, v in pairs(encs) do grade = math.max(grade, v.grade) gradeSum = gradeSum + v.grade * coeff if v:HasTag( "legendary" ) then isLegendary = true end end gradeSum = gradeSum + grade * (0x1 - coeff) local unwrappable = self.components.unwrappable local itemdata = unwrappable and unwrappable.itemdata local num = IsTable(itemdata) and #itemdata local rarity2 = 0x0 if num and num > 0x0 then for i = 0x1, num do local persistData = IsTable(itemdata[i]) and itemdata[i].data local encNames = IsTable(persistData) and persistData.dycEnchantmentNames local num2 = IsTable(encNames) and #encNames if num2 and num2 > 0x0 then for j = 0x1, num2 do local encName = encNames[j] local enc = IsNonEmptyString(encName) and enchantmentList[encName] if enc then rarity2 = math.max(rarity2, enc:HasTag( "legendary" ) and 0xc8 or enc.grade) end end end end end return math.max(rarity2, isLegendary and 0xc8 or math.max(0x0, math.min(gradeSum, 0x64))) end function EntityScript:GetEnchantmentBonus(bonus) local encs = self:GetEnchantments() local value = 0x0 for k, v in pairs(encs) do value = value + v:GetBonus(bonus, self) end return value end function EntityScript:GetEnchantmentLines() local encs = self:GetEnchantments() local t = {} for k, v in pairs(encs) do local des = v:GetDescription(self) if des and type(des) == "string" and #des > 0x0 then table.insert(t, {text = des, color = v.desColor, isHidden = v.isHidden}) end end return t end function EntityScript:GetEnchantmentLongDescription() local encs = self:GetEnchantments() local longDes = nil local longDesList = {} for k, v in pairs(encs) do local des = v:GetLongDescription(self) if des and type(des) == "string" and #des > 0x0 then table.insert(longDesList, {des = des, priority = v.priority}) end end if #longDesList > 0x0 then table.sort(longDesList, function(a, b) return a.priority > b.priority end) for i = 0x1, #longDesList do local des = longDesList[i].des longDes = longDes ~= nil and longDes.." "..des or des end end return longDes end function EntityScript:GetEnchantmentsWithTag(tag) local encs = self:GetEnchantments() local list = {} for k, enc in pairs(encs) do if enc:HasTag(tag) then table.insert(list, enc) end end return list end function EntityScript:GetRandomEnchantment(yesTags, noTags) yesTags = yesTags or {} noTags = noTags or {} local encs = self:GetEnchantments() local list = {} for k, enc in pairs(encs) do local yes = 0x0 for _, tag in pairs(noTags) do if enc:HasTag(tag) then yes = - 0x1 break end end if yes == 0x0 and #yesTags <= 0x0 then yes = 0x1 end if yes == 0x0 then for _, tag in pairs(yesTags) do if enc:HasTag(tag) then yes = 0x1 break end end end if yes > 0x0 then table.insert(list, enc) end end return #list > 0x0 and list[math.random(#list)] end function EntityScript:GetEnchantmentCount(yesTags, noTags) yesTags = yesTags or {} noTags = noTags or {} local encs = self:GetEnchantments() local count = 0x0 for k, enc in pairs(encs) do if not enc.isHidden then local yes = 0x0 for _, tag in pairs(noTags) do if enc:HasTag(tag) then yes = - 0x1 break end end if yes == 0x0 and #yesTags <= 0x0 then yes = 0x1 end if yes == 0x0 then for _, tag in pairs(yesTags) do if enc:HasTag(tag) then yes = 0x1 break end end end if yes > 0x0 then count = count + 0x1 end end end return count end function EntityScript:GetEnchantments() if not self.dycEnchantments then self.dycEnchantments = {} end return self.dycEnchantments end function EntityScript:GetEnchantment(name) return self:GetEnchantments()[name] or nil end local function InvokeEnchantmentTimePhaseChange(self) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.timePhaseChangeFn if fn then fn(v, self) end end end function EntityScript:AddEnchantment(name, addTest) if not name or type(name) ~= "string" then print( "Enchantment name required!" ) return end local encs = self:GetEnchantments() local enc = enchantmentList[name] if enc then if encs[name] then if not self.dycNoEncPrint then print(tostring(enc).." already exists!" ) end elseif not addTest or enc:CanAdd(self) then encs[name] = enc if self.components.combat then local health = self.components.health local oldhp = health and health:GetPercent() self:RecalcCharacterEnchantmentBonus(bonusList) if oldhp then health:SetPercent(oldhp) end end local equippable = self.components.equippable if equippable and equippable.owner then local health = equippable.owner.components.health local oldhp = health and health:GetPercent() equippable.owner:RecalcCharacterEnchantmentBonus(bonusList) if oldhp then health:SetPercent(oldhp) end end enc:OnAdd(self) if enc.timePhaseChangeFn and not self.dycTimePhaseEventListened then self.dycTimePhaseEventListened = true local world = GetWorld() local fn = function(inst, data) InvokeEnchantmentTimePhaseChange(self) end self:ListemForEvent( "daytime" , fn, world) self:ListemForEvent( "dusktime" , fn, world) self:ListemForEvent( "nighttime" , fn, world) end if self.OnEnchantmentChange then self.OnEnchantmentChange(self) end return enc else if not self.dycNoEncPrint then print( "Cannot add "..tostring(enc).." to "..tostring(self).."." ) end end else if not self.dycNoEncPrint then print( "Enchantment "..name.." does not exist!" ) end end end function EntityScript:RemoveEnchantment(name) if name and type(name) == "table" then name = name.name end if not name or type(name) ~= "string" then print( "Enchantment name required!" ) return end local encs = self:GetEnchantments() local enc = enchantmentList[name] local hasEnc = encs[name] ~= nil encs[name] = nil if self.components.combat then local health = self.components.health local oldhp = health and health:GetPercent() self:RecalcCharacterEnchantmentBonus(bonusList) if oldhp then health:SetPercent(oldhp) end end local equippable = self.components.equippable if equippable and equippable.owner then local health = equippable.owner.components.health local oldhp = health and health:GetPercent() equippable.owner:RecalcCharacterEnchantmentBonus(bonusList) if oldhp then health:SetPercent(oldhp) end end if hasEnc then enc:OnRemove(self) end if self.OnEnchantmentChange then self.OnEnchantmentChange(self) end end function EntityScript:RemoveAllEnchantments() local encs = self:GetEnchantments() for k, v in pairs(encs) do self:RemoveEnchantment(k) end end function EntityScript:InvokeEventEquip(owner, slot) local encs = self:GetEnchantments() for k, v in pairs(encs) do v:OnEquip(self, owner, slot) end end function EntityScript:InvokeEventUnequip(owner, slot) local encs = self:GetEnchantments() for k, v in pairs(encs) do v:OnUnequip(self, owner, slot) end end function EntityScript:InvokeEventAttack(attacker, target, weapon, projectile) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.attackFn if fn then fn(v, self, attacker, target, weapon, projectile) end end end function EntityScript:InvokeEventPreDamage(attacker, target, weapon, damage) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.preDamageFn if fn then fn(v, self, attacker, target, weapon, damage) end end end function EntityScript:InvokeEventDamage(attacker, target, weapon, damage) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.damageFn if fn then fn(v, self, attacker, target, weapon, damage) end end local infos = self:GetBuffs() for k, info in pairs(infos) do local fn = info.buff.damageFn if fn then fn(info.buff, info, attacker, target, weapon, damage) end end end function EntityScript:InvokeEventAttacked(target, attacker, weapon, projectile) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.attackedFn if fn then fn(v, self, target, attacker, weapon, projectile) end end end function EntityScript:InvokeEventPreDamaged(target, attacker, weapon, damage) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.preDamagedFn if fn then fn(v, self, target, attacker, weapon, damage) end end end function EntityScript:InvokeEventDamaged(target, attacker, weapon, damage) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.damagedFn if fn then fn(v, self, target, attacker, weapon, damage) end end local infos = self:GetBuffs() for k, info in pairs(infos) do local fn = info.buff.damagedFn if fn then fn(info.buff, info, target, attacker, weapon, damage) end end end function EntityScript:InvokeEventTarget(attacker, target) local encs = self:GetEnchantments() for k, v in pairs(encs) do local fn = v.targetFn if fn then fn(v, self, attacker, target) end end end function EntityScript:IsQualitySet() return self.dycQualitySet == true end function EntityScript:GetQualityString() local q = self:GetQuality() local qualityStr = QualityValueToString(q) local l = G.localization return qualityStr and l:GetString(qualityStr) or "" end function EntityScript:GetQuality() return self.dycQuality or 0x1 end function EntityScript:SetQuality(q) q = q or 0x1 self.dycQuality = q self.dycQualitySet = true if self.OnQualityChange then self.OnQualityChange(self, q) end end function EntityScript:SetRandomQuality(min, max) min = min or 0.75 max = max or 1.25 self:SetQuality(RandomFloat(min, max)) end function EntityScript:RecalcCharacterEnchantmentBonus(data) if type(data) == "table" then for k, name in pairs(data) do self:RecalcCharacterEnchantmentBonus(name) end elseif type(data) == "string" then local name = data local inv = self.components.inventory local equipslots = inv and inv.equipslots local bonus = 0x0 if equipslots then for k, v in pairs(equipslots) do bonus = bonus + v:GetEnchantmentBonus(name) end end bonus = bonus + self:GetEnchantmentBonus(name) self["dycEnchantmentBonusSum_"..name] = bonus end end function EntityScript:GetCharacterEnchantmentBonus(name) return self["dycEnchantmentBonusSum_"..name] or 0x0 end function EntityScript:GetBuffs() if not self.buffInfos then self.buffInfos = {} end return self.buffInfos end function EntityScript:GetSortedBuffs() local infos = self:GetBuffs() local newInfos = {} for k, v in pairs(infos) do table.insert(newInfos, v) end table.sort(newInfos, function(a, b) if a.buff.isHidden and not b.buff.isHidden then return false elseif not a.buff.isHidden and b.buff.isHidden then return true end if a.buff.type == "positive" and b.buff.type == "negative" then return true elseif a.buff.type == "negative" and b.buff.type == "positive" then return false end return a.buff.priority > b.buff.priority end) return newInfos end function EntityScript:GetBuffsWithTag(tag) local infos = self:GetBuffs() local list = {} for k, info in pairs(infos) do if info.buff:HasTag(tag) then table.insert(list, info) end end return list end function EntityScript:GetBuff(name) return self:GetBuffs()[name] or nil end local function BuffUpdate(self) local infos = self:GetBuffs() if next(infos) and not self.dycBuffUpdateTask then self.dycBuffUpdateTask = self:DoPeriodicTask(FRAMES, function() local infos = self:GetBuffs() for k, info in pairs(infos) do info.buff:Update(info, FRAMES) end end) elseif next(infos) == nil and self.dycBuffUpdateTask then self.dycBuffUpdateTask:Cancel() self.dycBuffUpdateTask = nil end end function EntityScript:SetBuffData(name, data) if not name or type(name) ~= "string" then print( "Buff name required!" ) return end if not data or not next(data) then return end local infos = self:GetBuffs() local info = infos[name] if info then info.buff:SetData(info, data) if self.OnBuffChange then self.OnBuffChange(self) end self:PushEvent( "buffchange" ) end end function EntityScript:AddBuff(name, doer) if not name or type(name) ~= "string" then print( "Buff name required!" ) return end local infos = self:GetBuffs() local buff = Buff.buffList[name] if buff then local info = infos[name] if info then buff:ChangeStack(info, 0x1, false) else info = {inst = self, source = doer and doer.prefab, buff = buff} infos[name] = info buff:OnAdd(info) end if self.OnBuffChange then self.OnBuffChange(self) end self:PushEvent( "buffchange" ) BuffUpdate(self) return info else print( "Buff "..name.." does not exist!" ) end end function EntityScript:RemoveBuff(name) if not name or type(name) ~= "string" then print( "Buff name required!" ) return end local infos = self:GetBuffs() local info = infos[name] infos[name] = nil if info then info.buff:OnRemove(info) end if self.OnBuffChange then self.OnBuffChange(self) end self:PushEvent( "buffchange" ) BuffUpdate(self) end function EntityScript:RemoveAllBuffs() local infos = self:GetBuffs() for k, v in pairs(infos) do self:RemoveBuff(k) end end function EntityScript:GetBuffBonus(bonus) local infos = self:GetBuffs() local value = 0x0 for k, info in pairs(infos) do value = value + info.buff:GetBonus(bonus, info) end return value end function EntityScript:GetCharacterBonus(bonus) return self:GetCharacterEnchantmentBonus(bonus) + self:GetBuffBonus(bonus) end local oldGetDisplayName = EntityScript.GetDisplayName function EntityScript:GetDisplayName() local nameStr = self.prefab and STRINGS.NAMES[string.upper(self.prefab)] if nameStr and type(nameStr) == "string" then self.name = nameStr end return oldGetDisplayName(self) end local oldGetPersistData = EntityScript.GetPersistData function EntityScript:GetPersistData(...) local data, references = oldGetPersistData(self, ...) if self.dycQuality then if not data then data = {} end data.dycQuality = self.dycQuality end if self.dycGameData then if not data then data = {} end data.dycGameData = {} for k, v in pairs(self.dycGameData) do if v and type(v) ~= "function" then data.dycGameData[k] = v end end end local encs = self:GetEnchantments() if next(encs) then if not data then data = {} end local encNames = {} for k, v in pairs(encs) do table.insert(encNames, k) end data.dycEnchantmentNames = encNames end local infos = self:GetBuffs() if next(infos) then if not data then data = {} end local buffDatas = {} for k, info in pairs(infos) do table.insert(buffDatas, info.buff:GetPersistData(info)) end data.dycBuffDatas = buffDatas end return data, references end local oldSetPersistData = EntityScript.SetPersistData function EntityScript:SetPersistData(data, newents, ...) if data and data.dycQuality then self:SetQuality(data.dycQuality) end if data and data.dycGameData and self.dycGameData then for k, v in pairs(data.dycGameData) do self.dycGameData[k] = v end end if data and data.dycEnchantmentNames then for k, v in pairs(data.dycEnchantmentNames) do if enchantmentList[v] then self:AddEnchantment(v) end end end if data and data.dycBuffDatas then for k, v in pairs(data.dycBuffDatas) do local name = type(v) == "table" and v.name if name and Buff.buffList[name] then self:AddBuff(name) v.name = nil self:SetBuffData(name, v) end end end return oldSetPersistData(self, data, newents, ...) end local oldPushBufferedAction = EntityScript.PushBufferedAction function EntityScript:PushBufferedAction(bufferedaction, ...) if bufferedaction then if bufferedaction.action == ACTIONS.CASTSPELL then if self == GetPlayer() and not bufferedaction.pos and TheInput.mouse_enabled then bufferedaction.pos = Input:GetWorldPosition() end end end return oldPushBufferedAction(self, bufferedaction, ...) end local oldRemove = EntityScript.Remove function EntityScript:Remove(...) self.dycIsRemoving = true self:RemoveAllBuffs() self:RemoveAllEnchantments() return oldRemove(self, ...) end local changedEventFns = {} local oldListenForEvent = EntityScript.ListenForEvent function EntityScript:ListenForEvent(event, fn, source, ...) local fn2 = fn local reboundPrefabList = {["armorcactus"] = true,["armor_bramble"] = true,} local reboundEventList = {["blocked"] = true,["attacked"] = true,} if event and fn2 and reboundEventList[event] then local isListedPrefab = self.prefab and reboundPrefabList[self.prefab] local isElephantcactus = self:HasTag( "elephantcactus" ) if isListedPrefab or isElephantcactus then local oldFn = fn2 local newFn = changedEventFns[fn] or function(owner, data, ...) if owner and owner.isNonAttDmg then return end local attacker = data and type(data) == "table" and data.attacker if attacker then attacker.isNonAttDmg = true end oldFn(owner, data, ...) if attacker then attacker.isNonAttDmg = nil end end fn2 = newFn changedEventFns[fn] = newFn end end return oldListenForEvent(self, event, fn2, source, ...) end local oldRemoveEventCallback = EntityScript.RemoveEventCallback function EntityScript:RemoveEventCallback(event, fn, source, ...) local fn2 = changedEventFns[fn] or fn return oldRemoveEventCallback(self, event, fn2, source, ...) end if not EntityScript.GetRotation then function EntityScript:GetRotation() return self.Transform:GetRotation() end end 